previewCss:
.darma-loader-uiverse-isometric-layer-tile {
  position: relative;
  width: 60px;
  height: 60px;
  background: var(--loader-color, #a19dad);
  transform: rotateX(65deg) rotate(45deg);
  color: var(--loader-secondary-color, #ffffff);
  animation: darma-loader-uiverse-isometric-layer-tile-layerStack 1s linear infinite alternate;
}
.darma-loader-uiverse-isometric-layer-tile::after {
  content: "";
  position: absolute;
  inset: 0;
  background: color-mix(in srgb, var(--loader-secondary-color, #ffffff) 70%, transparent);
  animation: darma-loader-uiverse-isometric-layer-tile-layerTravel 1s linear infinite alternate;
}
@keyframes darma-loader-uiverse-isometric-layer-tile-layerStack { 0% { box-shadow: 0 0 0 0; } 90%,100% { box-shadow: 20px 20px 0 -4px; } }
@keyframes darma-loader-uiverse-isometric-layer-tile-layerTravel { 0% { transform: translate(0,0) scale(1); } 100% { transform: translate(-25px,-25px) scale(1); } }

